  ('heelevel3-e0adf6cd-moex-00090', 'heelevel3-e0adf6cd', 'heelevel3-e0adf6cd-moex-113-3082b5f1', 'sub-heelevel3-e0adf6cd-06', NULL, 'single_choice', '臺東縣政府函成功鎮公所代為公告現有巷道，甲所有之土地屬於該現有巷道之一部分，下列敘述 何者正確？', '["認定現有巷道之主管機關為臺東縣成功鎮公所", "認定現有巷道之公告，自公告日起第3日生效", "現有巷道之認定，涉及人民財產權之限制，因行政處分未個別送達給相對人甲，故對甲不生效力", "甲不服該公告應向內政部提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:34+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "311", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "教育行政"}'::jsonb, NULL),
  ('heelevel3-e0adf6cd-moex-00091', 'heelevel3-e0adf6cd', 'heelevel3-e0adf6cd-moex-113-3082b5f1', 'sub-heelevel3-e0adf6cd-06', NULL, 'single_choice', '有關行政法院之管轄，下列敘述何者正確？', '["於高等行政法院增設地方行政訴訟庭，專責部分之第一審通常訴訟程序事件、簡易訴訟程序、 交通裁決、收容聲請等事件", "當事人不服由高等行政法院地方行政訴訟庭所作成之判決，而提出上訴由最高行政法院管轄", "以高等行政法院地方行政訴訟庭為第一審管轄法院之事件，高等行政法院高等行政訴訟庭依通 常訴訟程序審理並為判決者，最高行政法院應以高等行政法院高等行政訴訟庭無管轄權而廢棄 原判決", "聲請人、受裁定人或內政部移民署對高等行政法院地方行政訴訟庭所為收容聲請事件之裁定不 服者，應向最高行政法院為抗告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:34+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "311", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "教育行政"}'::jsonb, NULL),
